def information_gain(self, x, y, split):
    y0 = y[x < split]  
    y1 = y[x >= split]
    N = len(y)
    y0_len = len(y0)
    if y0_len == 0 or y0_len == N:  
        return 0
    p0 = float(len(y0)) / N
    p1 = 1 - p0
    return (
        entropy(y) - p0 * entropy(y0) - p1 * entropy(y1)
    )

