def compute_ued_simple(
    bundle: Bundle,
    key: str,
    R: np.ndarray,
    alpha: float,
    ABpairs=None,
) -> Bundle:
    for frame in bundle.frames:
        N = frame.N
        xyz = frame.xyz
        if ABpairs is None:
            ABpairs2 = []
            for A in range(len(N)):
                for B in range(A):
                    ABpairs2.append((A, B))
        else:
            ABpairs2 = ABpairs
        V = np.zeros_like(R)
        for A, B in ABpairs2:
            rAB = xyz[A, :] - xyz[B, :]
            RAB = math.sqrt(sum(rAB**2))
            SAB = math.sqrt(_ued_cross_sections[N[A]] * _ued_cross_sections[N[B]]) / RAB
