def bisect_static(num_rows, query, key_func):
    lo = 0
    hi = num_rows
    exists = True
    while True:
        i = (hi + lo) / 2
        curr = key_func(i)
        if curr == query:
            break
        elif hi - lo <= 1:
            exists = False
            break
        elif curr < query:
            lo = i
        else:
            hi = i
    if exists:
        for j in xrange(i, -1, -1):
            curr = key_func(j)
            if curr != query:
                return j + 1
    return 0

