def _distance(A: np.ndarray, B: np.ndarray, P: np.ndarray) -> float:
    if np.all(A == P) or np.all(B == P):
        return 0
    if np.arccos(np.dot((P - A) / norm(P - A), (B - A) / norm(B - A))) > np.pi / 2:
        return norm(P - A)
    if np.arccos(np.dot((P - B) / norm(P - B), (A - B) / norm(A - B))) > np.pi / 2:
        return norm(P - B)
    return norm(np.cross(A - B, A - P)) / norm(B - A)

def minversion(module, version, inclusive=True, version_path="__version__"):
    if isinstance(module, types.ModuleType):
        module_name = module.__name__
    elif isinstance(module, str):
        module_name = module
        try:
            module = resolve_name(module_name)
        except ImportError:
            return False
    else:
        raise ValueError(
            "module argument must be an actual imported "
            "module, or the import name of the module; "
            "got {0!r}".format(module)
        )
    if "." not in version_path:
        have_version = getattr(module, version_path)
    else:
        have_version = resolve_name(".".join([module.__name__, version_path]))
    try:
        from pkg_resources import parse_version
    except ImportError:
        from packaging.version import Version as parse_version
    if inclusive:
        return parse_version(have_version) >= parse_version(version)
    else:
        return parse_version(have_version) > parse_version(version)

