    if end - start < 536870912:
        offsets = [585, 73, 9, 1]
    else:
        raise BigException
        offsets = [4681, 585, 73, 9, 1]
    binFirstShift = 17
    binNextShift = 3
    start = start >> binFirstShift
    end = (end - 1) >> binFirstShift
    bins = [1]
