def convert_newlines(
    fname: str,
    in_place: bool = True,
    tmp_dir: Optional[str] = None,
    tmp_prefix: Optional[str] = "gxupload",
    block_size: int = 128 * 1024,
    regexp=None,
):
    i = 0
    NEWLINE_BYTE = 10
    CR_BYTE = 13
    with tempfile.NamedTemporaryFile(
        mode="wb", prefix=tmp_prefix, dir=tmp_dir, delete=False
    ) as fp, open(fname, mode="rb") as fi:
        last_char = None
        block = fi.read(block_size)
        last_block = b""
        while block:
            if last_char == CR_BYTE and block.startswith(b"\n"):
                block = block[1:]
            if block:
                last_char = block[-1]
                block = block.replace(b"\r\n", b"\n").replace(b"\r", b"\n")
                if regexp:
                    block = b"\t".join(regexp.split(block))
                fp.write(block)
                i += block.count(b"\n")
                last_block = block
                block = fi.read(block_size)
        if last_block and last_block[-1] != NEWLINE_BYTE:
            i += 1
            fp.write(b"\n")
    if in_place:
        shutil.move(fp.name, fname)
        return (i, None)
    else:
        return (i, fp.name)

