    self.mResults = []
    if self.mNumJobs:
        chunks = range(0, len(self.mJobs), self.mNumJobs)
        chunks.append(len(self.mJobs))
    else:
        chunks = [0, len(self.mJobs)]
    for x in range(len(chunks) - 1):
        pids = []
        for job in self.mJobs[chunks[x] : chunks[x + 1]]:
            pid = os.fork()
            if not pid:
                os.nice(20)
                out, err = self.__runJob(job)
