    node = self._root
    succ_node = None
    while node is not None:
        cmp = self._cmp(self._cmp_data, key, node.key)
        if cmp == 0:
            break
        elif cmp < 0:
            if (succ_node is None) or self._cmp(
                self._cmp_data, node.key, succ_node.key
            ) < 0:
                succ_node = node
            node = node.left
        else:
            node = node.right
    if node is None:  
        if default is _sentinel:
            raise KeyError(str(key))
        return default
    if node.right is not None:
        node = node.right
        while node.left is not None:
            node = node.left
        if succ_node is None:
            succ_node = node
        elif self._cmp(self._cmp_data, node.key, succ_node.key) < 0:
            succ_node = node
    elif succ_node is None:  
        if default is _sentinel:
            raise KeyError(str(key))
        return default
    return succ_node.key, succ_node.value

