    elo_home_team = float(elo_df.loc[elo_df["Team"] == home_team, "Elo"].values[0])
    exp_win_away_team = 1 / (1 + 10 ** ((elo_home_team - elo_away_team) / 400))
    exp_win_home_team = 1 / (1 + 10 ** ((elo_away_team - elo_home_team) / 400))
