def _InternalRecursiveProbe(path, visited_path, results, read_method):
    path = os.path.realpath(path)
    if path in visited_path:
        return
    if os.path.isdir(path):
        data = read_method(path)
        for result in data:
            if result not in results:
                results.append(result)
        entries_list = os.listdir(path)
        visited_path.add(path)
    else:
        return
    for filename in entries_list:
        if filename == "subsystem":
            continue
        sub_path = os.path.join(path, filename)
        _InternalRecursiveProbe(sub_path, visited_path, results, read_method)
    return

def _parse_shell_script(self, path):
    try:
        scall = Popen([path, "--signature"], stdout=PIPE, stderr=PIPE)
        scall.wait()
    except OSError as error:
        self.log.info(
            "failed to read signature from D-Bus shell script '%s' (%s) "
            % (path, str(error))
        )
        return
    if scall.returncode != 0:
        self.log.info(
            "failed to read signature from D-Bus shell script '%s' (%s) "
            % (path, scall.stderr.read())
        )
    sig = {}
    try:
        sig = loads(scall.stdout.read())
        if not (("in" in sig and type(sig["in"]) == list) or "in" not in sig):
            self.log.debug(
                "failed to undertand in-signature of D-Bus shell script '%s'" % (path)
            )
        elif "out" not in sig or type(sig["out"]) not in [str, unicode]:
            self.log.debug(
                "failed to undertand out-signature of D-Bus shell script '%s'" % (path)
            )
        else:
            return (os.path.basename(path), sig, path)
    except ValueError:
        self.log.debug(
            "failed to undertand signature of D-Bus shell script '%s'" % (path)
        )
    return None

def eq(val=None):
    def ret_fn(x, pred, conf, label=None, meta=None):
        gt = val if val is not None else label
        if pred == gt or val is None:
            return True
        elif is_1d_list(gt):
            if len(gt) == len(pred):
                return False
            else:
                if not meta:
                    raise Exception("Cannot compare two sequences ")
                return compare_preds_with_mismatched_tokens(pred, gt, meta)
        elif type(gt) == str:
