def max(x):
    if np.isscalar(x) or type(x).__name__ in SCALAR_OBJS:
        return x
    elif type(x) is not cvxpy_matrix and type(x).__name__ not in ARRAY_OBJS:
        raise TypeError("Invalid argument type")
    if x.shape == (1, 1):
        return x[0, 0]
    t = variable()
    z = variable(x.shape[0], x.shape[1])
    constr = []
    for i in range(0, x.shape[0], 1):
        for j in range(0, x.shape[1], 1):
