def until_not(self, method, message=""):
    end_time = time.time() + self._timeout
    while True:
        try:
            value = method(self._obj)
            if not value:
                return value
        except self._ignored_exceptions as exc:
            return True
        time.sleep(self._poll)
        if time.time() > end_time:
