def hash_dir(
    dirpath,
    crypto=sha256,
    ignore_hidden_files=False,
    ignore_hidden_dirs=False,
    raise_notfound=True,
):
    from .specs import LazyField
    if dirpath is None or isinstance(dirpath, LazyField) or isinstance(dirpath, list):
        return None
    if not Path(dirpath).is_dir():
        if raise_notfound:
            raise FileNotFoundError(f"Directory {dirpath} not found.")
        return None
    file_hashes = []
    for dpath, dirnames, filenames in os.walk(dirpath):
        dirnames.sort()
        filenames.sort()
        dpath = Path(dpath)
        if ignore_hidden_dirs and dpath.name.startswith(".") and str(dpath) != dirpath:
            continue
        for filename in filenames:
            if ignore_hidden_files and filename.startswith("."):
                continue
            this_hash = hash_file(dpath / filename)
            file_hashes.append(this_hash)
    crypto_obj = crypto()
    for h in file_hashes:
        crypto_obj.update(h.encode())
    return crypto_obj.hexdigest()

def negation_status(word, pos, lemma, use_affixes=False):
    word = word.lower()
    match = False
    kind = None
    if word in self.lexicon["WHOLEWORD"]:
        match = True
        kind = "wholeword"
    elif lemma in self.lexicon["LEMMA"]:
        match = True
        kind = "lemma"
    elif use_affixes:
        if pos.lower().startswith("v"):
            prefixed, prefix = self.prefix_check(word, self.lexicon["VERB_STARTSWITH"])
            if prefixed:
                match = True
                kind = "verb-prefix-" + prefix
        elif pos.lower.startswith("n"):
            prefixed, prefix = self.prefix_check(word, self.lexicon["NOUN_STARTSWITH"])
            if prefixed:
                match = True
                kind = "noun-prefix-" + prefix
        elif pos.lower() in {"adj", "jj"}:
            prefixed, prefix = self.prefix_check(word, self.lexicon["ADJ_STARTSWITH"])
            if prefixed:
                match = True
                kind = "adj-prefix-" + prefix
            suffixed, suffix = self.suffix_check(word, self.lexicon["ADJ_ENDSWITH"])
            if suffixed:
                match = True
                kind = "adj-suffix-" + suffix
    return match, kind

