def calc_weight(cells, element):
    if not element.is_boundary:
        d_1 = (
            np.dot(element.n_v, element.x_v - cells[element.cell_ids[0]].x_v)
            / element.area
        )
        d_2 = (
            np.dot(element.n_v, cells[element.cell_ids[1]].x_v - element.x_v)
            / element.area
        )
        if d_1 + d_2 > 1e-16:
            weight = d_1 / (d_1 + d_2)
        else:
            raise ValueError("Weight", d_1 + d_2)
    else:
        weight = 1.0
    return weight

