    for x in range(len(current)):
        if x == 0:
            if current[0] != 3:
                raise IOError(f"{current[0]} passed to Avg reverse filter")
            continue
        prior = previous[x] if previous else 0
        raw = current[x - bpp] if x - bpp > 0 else 0
        current[x] = (current[x] + math.floor((raw + prior) / 2)) % 256
    return current

