def parse_uri(uri: str) -> Tuple[str, str]:
    parsed = urlparse(uri)
    if parsed.scheme == "file":
        path = url2pathname(parsed.path)
        if os.name == "nt":
            netloc = url2pathname(parsed.netloc)
            path = path.lstrip("\\")
            path = re.sub(r"^([a-z]):", _uppercase_driveletter, path)
            if netloc:
                return parsed.scheme, "\\\\{}\\{}".format(netloc, path)
            else:
                return parsed.scheme, path
        return parsed.scheme, path
    return parsed.scheme, uri

def minibatch_parse(sentences, model, batch_size):
    dependencies = []
    import math
    for batch in range(int(math.ceil(len(sentences) / batch_size))):
        start_idx = batch * batch_size
        partialParses = [
            PartialParse(sentence)
            for sentence in sentences[start_idx : start_idx + batch_size]
        ]
        unfin_partialParses = partialParses
        while len(unfin_partialParses) != 0:
            transitions = model.predict(unfin_partialParses)
            for idx, transition in enumerate(transitions):
                unfin_partialParses[idx].parse([transition])
            unfin_partialParses = list(
                filter(lambda p: len(p.stack) != 1, unfin_partialParses)
            )
        for p in partialParses:
            dependencies.append(p.dependencies)
    return dependencies

