def update_certificate_and_wait_for_state(
    self, certificate_id, wait_for_states=[], operation_kwargs={}, waiter_kwargs={}
):
    operation_result = self.client.update_certificate(
        certificate_id, **operation_kwargs
    )
    if not wait_for_states:
        return operation_result
    lowered_wait_for_states = [w.lower() for w in wait_for_states]
    wait_for_resource_id = operation_result.data.id
    try:
        waiter_result = oci.wait_until(
            self.client,
            self.client.get_certificate(wait_for_resource_id),
            evaluate_response=lambda r: getattr(r.data, "lifecycle_state")
            and getattr(r.data, "lifecycle_state").lower() in lowered_wait_for_states,
            **waiter_kwargs
        )
        result_to_return = waiter_result
        return result_to_return
    except Exception as e:
        raise oci.exceptions.CompositeOperationError(
            partial_results=[operation_result], cause=e
        )

