def GetA(fun, x, direction, coordinate_rotation=False):
    if x.shape != (2,) or direction.shape != (2,):
        x = x.reshape(
            -1,
        )
        direction = direction.reshape(
            -1,
        )
    a = sy.Symbol("a", real=True)  
    fun = fun(x[0] + a * direction[0], x[1] + a * direction[1])  
    diff_fun = sy.diff(fun, a)  
    for value in sy.solve(diff_fun, a):
        if not coordinate_rotation:  
            return value
        else:  
            return value
    return None

