        ]
    else:
        raise ValueError
    tomo_lbl, num_lbls = sp.ndimage.label(
        tomo >= b_th, structure=np.ones(shape=[3, 3, 3])
    )
    tomo_out = np.zeros(shape=tomo.shape, dtype=np.int)
    lut = np.zeros(shape=num_lbls + 1, dtype=np.int)
    for x in range(tomo.shape[0]):
