        or tf.reduce_sum(tf.cast(tf.math.greater(axis_1, 1), tf.float32)) == 2
        or tf.reduce_sum(tf.cast(tf.math.less(axis_0, 0), tf.float32)) == 2
        or tf.reduce_sum(tf.cast(tf.math.less(axis_1, 0), tf.float32)) == 2
