def epoch_policy(max_epoch=10, verbose=True):
    prev_val_loss = None
    loss, val_loss = yield True
    assert isinstance(loss, (int, float)), "Wrong type for loss {}: {}".format(
        loss, type(loss)
    )
    assert isinstance(val_loss, (int, float)), "Wrong type for loss {}: {}".format(
        val_loss, type(val_loss)
    )
    for _ in range(max_epoch - 1):
        reason = ""
        if prev_val_loss is not None and prev_val_loss > val_loss:
            reason = "Validation loss decreased"
        elif val_loss < loss:
            reason = "Validation loss is lower than loss."
        if loss / val_loss > 4:
            reason = ""  
        if reason:
            if verbose:
                print(reason)
            prev_val_loss = val_loss
            loss, val_loss = yield True
        else:
            break
    yield False

