def simplify_fraction(numer: int, denom: int):
    if denom == 0:
        raise ZeroDivisionError()
    if numer == denom:
        return 1, 1
    divide_by = gcd(numer, denom)
    numer //= divide_by
    denom //= divide_by
    if denom < 0:
        numer *= -1
        denom *= -1
    return numer, denom

