def find_individual_ancilla_values(
    ancilla_values, data_qubits, ancilla_qubits, label_string=""
):
    individual_ancilla_values = {
        label_string + str(count): 0
        for count in range(data_qubits + 1, data_qubits + 1 + ancilla_qubits)
    }
    for ancilla, value in ancilla_values.items():
        for count in range(ancilla_qubits):
            bit = ancilla[count]
            if bit == "1":
                key = label_string + str(data_qubits + ancilla_qubits - count)
