def apply_patch(self, target, patch):
    target_props = target["properties"]
    patch_props = patch["properties"]
    conflict = set(target_props) & set(patch_props)
    mergeable = set(self.rules)
    for name in conflict - mergeable:
        if target_props[name] != patch_props[name]:
            raise errors.UnresolvableConflict(
                "Cannot apply patch for attribute {0}: conflict".format(name)
            )
        conflict.remove(name)
    for name in conflict:
        try:
            target_props[name] = self.rules[name](target_props[name], patch_props[name])
        except Exception as e:
            raise errors.UnresolvableConflict(
                "Cannot apply patch for attribute {0}: {1}".format(name, e)
            )

def wait_for_ready_callbacks(self, *args, **kwargs):
    global g_wait_set_spinning_lock
    global g_wait_set_spinning
    with g_wait_set_spinning_lock:
        if g_wait_set_spinning:
            raise RuntimeError(
                "Executor.wait_for_ready_callbacks() called concurrently in multiple threads"
            )
        g_wait_set_spinning = True
    try:
        got_generator = False
        while not got_generator:
            if (
                self._cb_iter is None
                or self._last_args != args
                or self._last_kwargs != kwargs
            ):
                self._last_args = args
                self._last_kwargs = kwargs
                self._cb_iter = self._wait_for_ready_callbacks(*args, **kwargs)
                got_generator = True
            try:
                return next(self._cb_iter)
            except StopIteration:
                self._cb_iter = None
    finally:
        with g_wait_set_spinning_lock:
            g_wait_set_spinning = False

