def do_rmsprop(self, X, Y, update, learning_rate, **kwargs):
    layers = len(self.structure) - 1
    grads = self.calculate_grads(X, Y, kwargs["l2_reg_param"])
    for ii in np.arange(1, layers + 1):
        update["w" + str(ii)] = kwargs["beta"] * update.get("w" + str(ii), 0) + (
            1 - kwargs["beta"]
        ) * np.square(np.sum(grads["w" + str(ii)], axis=0))
        update["b" + str(ii)] = kwargs["beta"] * update.get("b" + str(ii), 0) + (
            1 - kwargs["beta"]
        ) * np.square(np.sum(grads["b" + str(ii)], axis=1).reshape(-1, 1))
        self.params["w" + str(ii)] -= np.multiply(
            (learning_rate / np.sqrt(kwargs["epsilon"] + update["w" + str(ii)])),
            np.sum(grads["w" + str(ii)], axis=0),
        )
        self.params["b" + str(ii)] -= np.multiply(
            (learning_rate / np.sqrt(kwargs["epsilon"] + update["b" + str(ii)])),
            np.sum(grads["b" + str(ii)], axis=1).reshape(-1, 1),
        )
    return update

