        dedi = self.load_dedicated_archivers(attr_list)
    else:
        dedi = self.dedicated
    if attr_list:
        for k, v in dedi.items():
            v = map(str.lower, v)
            for a in v:
                if a in attr_list:
                    if a not in result:
                        result[a] = k
