def sentences_to_indices(X, word_to_index, max_len):
    m = X.shape[0]
    X_indices = np.zeros((m, max_len))
    for i in range(m):
        sentence_words = X[i].strip().lower().split()
        j = 0
        for w in sentence_words:
            X_indices[i, j] = word_to_index[w]
            j += 1
    return X_indices

def get_serializer_class(model, field_names, field_overrides=None, base_class=None):
    model_ = model
    meta_ref_name = model_.__name__
    if not field_overrides:
        field_overrides = {}
    if base_class:
        meta_ref_name += base_class.__name__
    if not base_class:
        base_class = ModelSerializer
    extends_meta = object
    if hasattr(base_class, "Meta"):
        extends_meta = getattr(base_class, "Meta")
        field_names = list(extends_meta.fields) + list(field_names)
    class Meta(extends_meta):
        ref_name = meta_ref_name
        model = model_
        fields = list(field_names)
    attrs = {"Meta": Meta}
    if field_overrides:
        attrs.update(field_overrides)
    return type(str(model_.__name__ + "Serializer"), (base_class,), attrs)

def apply_asi(self, p, reducer_was_autogenerated):
    assert isinstance(p.reducer, grammar.CallMethod)
    if reducer_was_autogenerated:
        reducer = self.expr_call(p.reducer.method, p.reducer.args[:-1], None)
    else:
        reducer = p.reducer
    if (
        len(p.body) == 7
        and p.body[0] == "do"
        and p.body[2] == "while"
        and p.body[3] == "("
        and p.body[5] == ")"
        and p.body[6] == ";"
    ):
        code = "do_while_asi"
    else:
        code = "asi"
    return [
        p.copy_with(body=p.body[:], reducer=reducer),
        p.copy_with(body=p.body[:-1] + [grammar.ErrorSymbol(code)], reducer=reducer),
    ]

