    if pad:
        pad = data_len - pad
        self._local_params_byte_count += pad
    param_type = ParamType.LV1
    if 0xFFFF < self._local_params_byte_count:
        param_type = ParamType.LV4
    elif 0xFF < self._local_params_byte_count:
