    in_weight_sum = (
        np.sum(np.abs(in_weights), axis=0) + in_biases
    )  
    out_weight_sum = np.sum(
        np.abs(out_weights), axis=1
    )  
    output_fns, _, repeats, arg_nums = zip(*fns)
    input_iterator = generate_arguments(
        all_args=in_weight_sum, repeats=repeats, arg_nums=arg_nums
    )
    fn_iterator = yield_with_repeats(output_fns, repeats)
    count = sum(
        [
            complexity_of_node(out_weight, in_weights, fn, thresh)
            for out_weight, in_weights, fn in zip(
