def fix_circular_refs(o, _seen=None):
    _seen = _seen or set()
    if id(o) in _seen:
        return "<cycle>"
    _seen.add(id(o))
    res = o
    if isinstance(o, dict):
        res = {
            fix_circular_refs(k, _seen): fix_circular_refs(v, _seen)
            for k, v in o.items()
        }
