def check_front(self, grid):
    if not self.parts:
        return
    front_tile = grid[self.head.pos]
    if front_tile:
        if isinstance(front_tile, Number):
            if "+" in self.ope:
                self.inc += front_tile.value
                nbr_new = 2
            elif "-" in self.ope:
                self.inc -= front_tile.value
                nbr_new = 2
            for _ in range(nbr_new):
                self.behind_queue.append(Number())
        if isinstance(front_tile, Operation):
            self.ope = "change to " + front_tile.ope
            if front_tile.ope == "+":
                self.behind_queue.append(Operation("-"))
            elif front_tile.ope == "-":
                self.behind_queue.append(Operation("+"))
        elif front_tile in self.parts:
            self.dead = True

def show(self):
    buf = self._buf
    if self.brightness < 1.0:
        buf = bytearray(self._buf)
        for i in range(START_HEADER_SIZE):
            buf[i] = 0x00
        for i in range(START_HEADER_SIZE, self.end_header_index):
            buf[i] = (
                self._buf[i] if i % 4 == 0 else int(self._buf[i] * self._brightness)
            )
        for i in range(self.end_header_index, len(buf)):
            buf[i] = 0xFF
    if self._spi:
        self._spi.write(buf)

def get_y_positions(tree):
    maxheight = tree.count_terminals()
    heights = dict((tip, maxheight - i) for i, tip in enumerate(tree.get_terminals()))
    def calc_row(clade):
        for subclade in clade:
            if subclade not in heights:
                calc_row(subclade)
        heights[clade] = (heights[clade.clades[0]] + heights[clade.clades[-1]]) / 2.0
    if tree.root.clades:
        calc_row(tree.root)
    return heights

