def check_for_error_condition(conf, sess, x, preds, t, sens):
    t = np.array(t).astype("int")
    label = model_argmax(sess, x, preds, np.array([t]))
    for val in range(
        conf.input_bounds[sens - 1][0], conf.input_bounds[sens - 1][1] + 1
    ):
        if val != int(t[sens - 1]):
            tnew = copy.deepcopy(t)
            tnew[sens - 1] = val
            label_new = model_argmax(sess, x, preds, np.array([tnew]))
            if label_new != label:
                return val
    return t[sens - 1]

def hasText(self, contentWords=False, ignore_verbs=False):
