    if self.text() is not None: 
        if contentWords:
            if self.tag() in MATCH_STOP_TAGS:
                pass 
            elif ignore_verbs and self.tag() in VERB_PHRASE_TAGS:
                pass
            elif self.text().lower() in SyncGrammarTree.stopwords:
                pass 
            else:
                return True
