    from mindspore import nn, ops
    for item in operations:
        if isinstance(item, (nn.Cell, ops.Primitive)):
            raise ValueError(
                "Input operations should not contain network computing operator like in "
                "mindspore.nn or mindspore.ops, got operation:",
                str(item),
