def _encode_offt(x):
    if x < 0:
        x = -x
        sign = 0x80
    else:
        sign = 0
    bs = [0] * 8
    bs[0] = x % 256
    for b in xrange(7):
        x = (x - bs[b]) / 256
        bs[b + 1] = x % 256
    bs[7] |= sign
    if sys.version_info[0] < 3:
        return "".join(map(chr, bs))
    else:
        return bytes(bs)

