def wait_for_topics(self, timeout):
    rospy.loginfo("waiting for subscribed topics to be ready")
    loop_freq = 1  
    rate = rospy.Rate(loop_freq)
    simulation_ready = False
    for i in xrange(timeout * loop_freq):
