def graphflows(g, nomg, gtype="bipartite"):
    endflows = dict()
    if gtype == "normal":
        for edge in g.edges:
            flows = g.get_edge_data(edge[0], edge[1])
            nomflows = nomg.get_edge_data(edge[0], edge[1])
            for flow in flows:
                if flows[flow] != nomflows[flow]:
                    endflows[flow] = {}
                    vals = flows[flow]
                    for val in vals:
                        if vals[val] != nomflows[flow][val]:
                            endflows[flow][val] = flows[flow][val]
    elif gtype == "bipartite":
        for node in g.nodes:
            if g.nodes[node]["bipartite"] == 1:  
                if g.nodes[node]["states"] != nomg.nodes[node]["states"]:
                    endflows[node] = {}
                    vals = g.nodes[node]["states"]
                    for val in vals:
                        if vals[val] != nomg.nodes[node]["states"][val]:
                            endflows[node][val] = vals[val]
    return endflows

