def insert_iter(self, new_val):
    new = Node(new_val)
    parent = None
    current = self.root
    while current:
        parent = current
        if new_val < current.val:
            current = current.left
        else:
            current = current.right
    new.parent = parent
    if not parent:
        self.root = new
    elif new_val < parent.val:
        parent.left = new
    else:
        parent.right = new

