def regularSampleTValue(self, samples):
    lut = []
    length = self.length
    if length == 0:
        return []
    step = 1.0 / length
    t = 0
    while t <= 1.0:
        lut.append(
            (t, self.lengthAtTime(t))
        )  
        t += step
    desiredLength = 0.0
    rSamples = []
    while desiredLength < length:
        while len(lut) > 0 and lut[0][1] < desiredLength:
            lut.pop(0)
        if len(lut) == 0:
            break
        rSamples.append(lut[0][0])
        desiredLength += length / samples
    if rSamples[-1] != 1.0:
        rSamples.append(1.0)
    return rSamples

