def SingleColumnValueFilter(args, rows):
    op = args[2]
    column = "%s:%s" % (args[0], args[1])
    value = args[3]
    if value.startswith("binary:"):
        value = value[7:]
    r = {}
    for row in rows:
        data = rows[row]
        if op == "=":
            if column in data and data[column] == value:
                r[row] = data
        elif op == "<":
            if column in data and data[column] < value:
                r[row] = data
        elif op == "<=":
            if column in data and data[column] <= value:
                r[row] = data
        elif op == ">":
            if column in data and data[column] > value:
                r[row] = data
        elif op == ">=":
            if column in data and data[column] >= value:
                r[row] = data
        elif op == "!=":
            if column in data and data[column] != value:
                r[row] = data
    return r

