def low_pass_filter(seg, cutoff):
    RC = 1.0 / (cutoff * 2 * math.pi)
    dt = 1.0 / seg.frame_rate
    alpha = dt / (RC + dt)
    original = seg.get_array_of_samples()
    filteredArray = array.array(seg.array_type, original)
    frame_count = int(seg.frame_count())
    last_val = [0] * seg.channels
    for i in range(seg.channels):
        last_val[i] = filteredArray[i] = original[i]
    for i in range(1, frame_count):
        for j in range(seg.channels):
            offset = (i * seg.channels) + j
            last_val[j] = last_val[j] + (alpha * (original[offset] - last_val[j]))
            filteredArray[offset] = int(last_val[j])
    return seg._spawn(data=filteredArray)

def _machines_to_worker_map(
    machines: str, worker_addresses: Iterable[str]
) -> Dict[str, int]:
    machine_addresses = machines.split(",")
    if len(set(machine_addresses)) != len(machine_addresses):
        raise ValueError(
            f"Found duplicates in 'machines' ({machines}). Each entry in 'machines' must be a unique IP-port combination."
        )
    machine_to_port = defaultdict(set)
    for address in machine_addresses:
        host, port = address.split(":")
        machine_to_port[host].add(int(port))
    out = {}
    for address in worker_addresses:
        worker_host = urlparse(address).hostname
        if not worker_host:
            raise ValueError(
                f"Could not parse host name from worker address '{address}'"
            )
        out[address] = machine_to_port[worker_host].pop()
    return out

