def construct_neighbouring_sites(
    sites: List[PolyhedralSite],
) -> Dict[int, List[PolyhedralSite]]:
    neighbours: Dict[int, List[PolyhedralSite]] = {}
    for site_i in sites:
        neighbours[site_i.index] = []
        for site_j in sites:
            if site_i is site_j:
                continue
            n_shared_vertices = len(
                set(site_i.vertex_indices) & set(site_j.vertex_indices)
            )
            if n_shared_vertices >= 3:
                neighbours[site_i.index].append(site_j)
    return neighbours

