def _validate_and_split_len(self, key):
    if isinstance(key, tuple) and len(key) == self._len_keys:
        if any([not _is_good_iterable(v) and not isinstance(v, str) for v in key]):
            raise KeyError("The key {} is not valid.".format(key))
        key_types_list = [[v] if isinstance(v, str) else v for v in key]
        return list(product(*key_types_list))
    elif _is_iterable(key):
        keys = []
        for k in key:
            keys.extend(self._validate_and_split_len(k))
        return keys
    else:
        raise KeyError("The key {} is not valid.".format(key))

def add_node(self, node, mode=None):
    if self.is_root:
        self.add_child(node)
    elif mode is None:
        self.parent.add_child_after(node, self)
    elif mode.orient is self.parent.orient:
        if mode & AddMode.SPLIT:
            node._size = 0  
            self.parent.add_child_after(node, self)
            self._size = node._size = self.size / 2
        else:
            self.parent.add_child_after(node, self)
    else:
        self.flip_with(node)

