def fit(self, inputs, outputs, inspect=False):
    if inputs.ndim < 2:
        inputs = np.reshape(inputs, (len(inputs), -1))
    if outputs.ndim < 2:
        outputs = np.reshape(outputs, (len(outputs), -1))
    teachers_scaled = self._scale_teacher(outputs)
    if not self.silent:
        print("harvesting states...")
    extended_states = self.get_states(inputs, teachers_scaled, inspect)
    if not self.silent:
        print("fitting...")
    transient = min(int(inputs.shape[1] / 10), 100)
    self.W_out = np.dot(
        np.linalg.pinv(extended_states[transient:, :]),
        self.inverse_out_activation(teachers_scaled[transient:, :]),
    ).T
    if not self.silent:
        print("training error:")
    pred_train = self._unscale_teacher(
        self.out_activation(np.dot(extended_states, self.W_out.T))
    )
    if not self.silent:
        print(np.sqrt(np.mean((pred_train - outputs) ** 2)))
    return pred_train

def move_emitters(self):
    moved_emitters = []
    for e_pos, e_dir, e_vel, e_range, e_color, e_pal in self.emitters:
        e_pos = e_pos + e_vel
        if e_vel > 0:
            if e_pos >= (self._end + 1):
                if self.wrap:
                    e_pos = e_pos - (self._end + 1) + self._start
                else:
                    continue  
        else:
            if e_pos < self._start:
                if self.wrap:
                    e_pos = e_pos + self._end + 1 + self._start
                else:
                    continue  
        moved_emitters.append((e_pos, e_dir, e_vel, e_range, e_color, e_pal))
    self.emitters = moved_emitters

