def compress(self, condition, axis=None, out=None):
    a = self
    if condition.ndim != 1:
        raise ValueError("Dimension mismatch: condition must be a 1D array")
    if condition.dtype != bool:
        runtime.warn(
            "converting condition to bool type",
            category=RuntimeWarning,
        )
        condition = condition.astype(bool)
    if axis is None:
        axis = 0
        a = self.ravel()
    if a.shape[axis] < condition.shape[0]:
        raise ValueError(
            "Shape mismatch: " "condition contains entries that are out of bounds"
        )
    elif a.shape[axis] > condition.shape[0]:
        slice_tuple = tuple(slice(None) for ax in range(axis)) + (
            slice(0, condition.shape[0]),
        )
        a = a[slice_tuple]
    index_tuple = tuple(slice(None) for ax in range(axis))
    index_tuple += (condition,)
    if out is not None:
        out[:] = a[index_tuple]
        return out
    else:
        res = a[index_tuple]
        return res

