def get_heap_parameters(self):
    tokens = self.tokens[: len(self.tokens) / 2]
    tokens = list(set(tokens))
    common_words = self.get_common_words()
    vocabulary = list(set(tokens) - set(common_words))
    (k, b) = (0, 0)
    try:
        token_size, half_token_size = float(self.get_tokens_size()), float(
            self.get_tokens_size() / 2
        )
        vocabulary_size, half_vocabulary_size = float(self.get_vocabulary_size()), len(
            vocabulary
        )
        b = log(vocabulary_size / half_vocabulary_size) / log(
            token_size / half_token_size
        )
        k = (vocabulary_size + half_vocabulary_size) / float(
            pow(token_size, b) + pow(half_token_size, b)
        )
    except ValueError:
        print("Oups you're trying to get the log of 0")
    except ZeroDivisionError:
        print("Oups you're trying to divide by zero")
    return (k, b)

