def partial2hex(partial_order, n_inputs, n_outputs):
    par_bit_matrix = np.zeros(
        [n_outputs, 2**n_inputs], dtype=int
    )  
    for k in range(n_outputs):  
        indx = partial_order.index(-(k + 1))  
        indx_left = [
            n for n in partial_order[:indx] if n >= 0
        ]  
        bit_array = np.ones(
            2**n_inputs, dtype=int
        )  
        bit_array[indx_left] = 0  
        par_bit_matrix[k] = list(reversed(bit_array))  
    par_bit_code = "".join(
        map(str, par_bit_matrix.flatten("F"))
    )  
    n_nibbles = (
        (len(par_bit_code) - 1) // 4
    ) + 1  
    fmt = "0" + str(n_nibbles) + "X"  
    par_hex_code = format(int(par_bit_code, 2), fmt)  
    return par_hex_code

