def singleLoop(self, moments, epsilon=10**-5, factor=5, variant=1, maxIter=100_000):
    stDev = centeredMoment(moments, 2) ** 0.5
    mu2 = [
        float(i) * epsilon * factor * stDev + moments[0]
        for i in range(1, int(1 / epsilon))
    ]
    m2n = M2N(moments)
    err_min = m2n.error
    d_results = {}
    for mu2_i in mu2:
        m2n.fit(mu2=mu2_i, epsilon=epsilon, variant=variant, maxIter=maxIter)
        if m2n.error < err_min:
            err_min = m2n.error
            (
                d_results["mu1"],
                d_results["mu2"],
                d_results["sigma1"],
                d_results["sigma2"],
                d_results["p1"],
            ) = [[p] for p in m2n.parameters]
            d_results["error"] = [err_min]
    return pd.DataFrame.from_dict(d_results)

