        phi = -np.pi * 0.5
    method = "linear" if linear else "logarithmic"
    return scipy.signal.chirp(
        np.arange(duration, step=period),
        fmin,
        duration,
        fmax,
        method=method,
        phi=phi / np.pi * 180,  
