def cumulative_dict(data, primary_key, resolution=0.01):
    def _cumulative(it):
        it_iter = iter(it)
        primary_iter = filter(
            lambda x: it[0][0] <= x[0] <= it[-1][0], data[primary_key]
        )
        res = []
        total = 0
        total_primary = 0
        done = False
        for i in filter(lambda _: not done, np.arange(it[0][0], it[-1][0], resolution)):
            try:
                while (x := next(it_iter))[0] < i:
                    total += x[1]
            except StopIteration:
                done = True
            try:
                while (x := next(primary_iter))[0] < i:
                    total_primary += x[1]
            except StopIteration:
                done = True
            res.append([i, total, total_primary])
        return res
    return {
        key: _cumulative(item)
        for key, item in filter(lambda x: x[0] != primary_key, data.items())
    }

