def get_cloud_watch_time_tuple_for_sms_events(
    sms_events: List[SMSEvent],
) -> Tuple[int, int]:
    creation_dates = [sms_event.created for sms_event in sms_events]
    if not creation_dates:
        return 1, 1
    creation_dates.sort()
    start = creation_dates[0] - timedelta(days=1)
    end = creation_dates[-1] + timedelta(days=1)
    start = int(start.timestamp() * 1000)
    end = int(end.timestamp() * 1000)
    return start, end

def __call__(self, data: Iterable[T], chunk_size: int = 1) -> Generator[R, None, None]:
    buffer = Buffer()
    def chunking(d):
        ch = []
        for x in d:
            ch.append(x)
            if len(ch) == chunk_size:
                yield ch
                ch = []
        if len(ch) > 0:
            yield ch
    data_cnt = 0
    finished_cnt = 0
    for i, chunk in enumerate(chunking(data)):
        self._work_queue.put((i, chunk))
        data_cnt += 1
        try:
            while True:
                res_i, res_chunk = self._results_queue.get(False)
                for ch in buffer(res_i, res_chunk):
                    finished_cnt += 1
                    for x in ch:
                        yield x
        except queue.Empty:
            pass
    while finished_cnt < data_cnt:
        res_i, res_chunk = self._results_queue.get()
        for ch in buffer(res_i, res_chunk):
            finished_cnt += 1
            for x in ch:
                yield x

