def base_ortho_36(n):
    from opf_python.universal import get_HNF_diagonals
    diags = get_HNF_diagonals(n)
    spHNFs = []
    for diag in diags:
        a = diag[0]
        c = diag[1]
        f = diag[2]
        if f % a == 0:
            if f % 2 == 0:
                es = [0, f // 2.0]
            else:
                es = [0]
            if c % 2 == 0:
                bs = [0, c // 2.0]
            else:
                bs = [0]
            for b in bs:
                b32 = -b * f / float(a)
                if b32 % c == 0:
                    for e in es:
                        b22 = -b * e / float(a)
                        g13 = -2 * b * e / float(c)
                        if b22 % c == 0 and g13 % f == 0 and e % a == 0:
                            for d in range(0, f, a):
                                b12 = -b * d / float(a)
                                g12 = 2 * d - d * d / float(a) - b12 * e / float(c)
                                g22 = 2 * e - d * e / float(a) - b22 * e / float(c)
                                if b12 % c == 0 and g12 % f == 0 and g22 % f == 0:
                                    HNF = [[a, 0, 0], [b, c, 0], [d, e, f]]
                                    spHNFs.append(HNF)
    return spHNFs

