async def create_connection(
    protocol_factory: Callable[[], asyncio.Protocol],
    host: HostType,
    port: PortType,
    *,
    loop: asyncio.AbstractEventLoop = None,
    **kwargs,
) -> Tuple[asyncio.Transport, asyncio.Protocol]:
    loop = loop or asyncio.get_event_loop()
    create_connected_sock_kwargs = dict(
        (arg, kwargs.pop(arg)) for arg in create_connected_sock_kwds if arg in kwargs
    )
    sock = await create_connected_sock(
        host, port, loop=loop, **create_connected_sock_kwargs
    )
    try:
        return await loop.create_connection(protocol_factory, sock=sock, **kwargs)
    except:
        sock.close()
        raise

