def split_tile_type(self, tile_type_pkey, tile_type_pkeys, split_direction, split_map):
    tiles_seen = set()
    tiles = []
    tops_to_split = []
    next_dir = SPLIT_NEXT_DIRECTIONS[split_direction]
    for tile in self.items:
        if id(tile) in tiles_seen:
            continue
        if tile.tile_type_pkey == tile_type_pkey:
            for tile in tile.walk_in_direction(next_dir):
                pass
            for tile in tile.walk_in_direction(OPPOSITE_DIRECTIONS[next_dir]):
                if id(tile) not in tiles_seen:
                    tiles_seen.add(id(tile))
                    if tile.tile_type_pkey == tile_type_pkey:
                        tiles.append(tile)
            tops_to_split.append(tile)
    for top in tops_to_split:
        self.split_in_dir(
            top, tile_type_pkey, tile_type_pkeys, split_direction, split_map
