def getDistancesForStreamline(slPoincare, globalcenter, slradius):
    mins = []
    maxs = []
    for i in range(slPoincare.shape[0]):  
        if slPoincare[i, 0] > 0:  
            if (
                slPoincare[i, 0] < slradius
            ):  
                mins.append(slPoincare[i, :])
            else:
                maxs.append(slPoincare[i, :])
    mins = np.array(mins)
    maxs = np.array(maxs)
    distances = []
    if mins.size:  
        mindex = np.argmin(
            np.absolute(mins[:, 1] - globalcenter[2])
        )  
        if np.absolute(mins[mindex, 1] - globalcenter[2]) < 0.1:
            distances.append(
                mins[mindex, 0]
            )  
    if maxs.size:
        maxdex = np.argmin(np.absolute(maxs[:, 1] - globalcenter[2]))
        if np.absolute(maxs[maxdex, 1] - globalcenter[2]) < 0.1:
            distances.append(maxs[maxdex, 0])
    return distances

