def _fork_and_supervise_child(cls):
    try:
        os.setpgid(0, 0)
    except OSError as e:
        if e.errno != errno.EPERM:
            raise
    pid = os.fork()
    if pid == 0:
        cls._orphan_this_process()
        return
    os.waitpid(pid, 0)
    while True:
        try:
            proc_group_children = get_proc_group_children()
            if proc_group_children:
                psutil.wait_procs(proc_group_children, timeout=1)
            else:
                cls._echo("All children are gone. Parent is exiting...\n")
                exit(0)
        except KeyboardInterrupt:
            cls._echo("\n")
            continue

def transform_delete(node, cidx):
    deleted_rows = []
    kept_rows = []
    for r in range(node.table.n_row):
        row = node.table.get_row(r)
        if row[cidx].is_empty:
            deleted_rows.append(row)
            continue
        kept_rows.append(node.table.get_row(r))
    table = Table(kept_rows)
    error = 0
    for row in deleted_rows:
        found = False
        for kept in kept_rows:
            if has_same_info(kept, row):
                found = True
                break
        if not found:
            error += sum((0 if c.is_empty else 1 for c in row))
    return Node(table, error=error, label="DELETE(%i)" % cidx)

