        raise HydroDSArgumentException(
            "{file_name} is not a valid netcdf file".format(file_name=output_netcdf)
        )
    url = self._get_dataservice_specific_url("concatenatenetcdf")
    payload = {
        "input_netcdf1": input_netcdf1_url_path,
        "input_netcdf2": input_netcdf2_url_path,
        "output_netcdf": output_netcdf,
    }
