def get_sequel_display_string(value_list):
    print("value_list", value_list)
    try:
        value_list = map(int, value_list)
        value_list = sorted(value_list)
    except:
        print("Not able to map value_list")
    output_string = ""
    previous_value = value_list[0]
    temp_list = [previous_value]
    for value in value_list:
        if value <= previous_value + 1:
            temp_list.append(value)
        else:
            temp_list = sorted(set(temp_list))
            if len(temp_list) == 1:
                output_string = output_string + unicode(temp_list[0])
            else:
                output_string = output_string + "%s-%s" % (temp_list[0], temp_list[-1])
            output_string += ", "
            temp_list = [value]
        previous_value = value
    if temp_list:
        temp_list = sorted(set(temp_list))
        if len(temp_list) == 1:
            output_string = output_string + unicode(temp_list[0])
        else:
            output_string = output_string + "%s-%s" % (temp_list[0], temp_list[-1])
    return output_string

def paragraph_reversal(p: str) -> str:
    sentence_breaks = [".", "?", "!"]
    sentences = []
    sentence = []
    state = "normal_text"
    for i in range(len(p)):
        if state == "normal_text":
            sentence.append(p[i])
            if p[i] in sentence_breaks:
                state = "punctuation"
        elif state == "punctuation":
            sentence.append(p[i])
            if p[i].strip() != "":
                state = "normal_text"
            else:
                state = "white_space"
        elif state == "white_space":
            if p[i].strip() == "":
                continue
            elif p[i].upper() == p[i]:
                sentences.append("".join(sentence))
                sentence = [p[i]]
            state = "normal_text"
    if sentence[-1].strip != "":
        sentences.append(" ")
    sentences.append("".join(sentence))
    for i in range(int(len(sentences) / 2)):
        temp = sentences[i]
        sentences[i] = sentences[len(sentences) - 1 - i]
        sentences[len(sentences) - 1 - i] = temp
    return "".join(sentences)

