def timestamp_to_datetime(
    timestamp: str, tz: Optional[str] = None
) -> Optional[datetime]:
    if not timestamp:
        return None
    try:
        if tz:
            return pendulum.parse(timestamp, tz=tz)
        return pendulum.parse(timestamp)
    except ValueError:
        return None

