def probe(self, row, col):
    if not self.valid_loc(row, col):
        print("invalid location")
        return True
    if self.viewed[row, col] == 1:
        print("repeat move is invalid")
        return True
    self.viewed[row, col] = 1
    if self.mines[row, col]:
        print("you lose!")
        return False
    if self.counts[row, col] == 0:
        for i in [-1, 0, 1]:
            for j in [-1, 0, 1]:
                new_col = col + i
                new_row = row + j
                if (
                    self.valid_loc(new_row, new_col)
                    and not self.viewed[new_row, new_col]
                ):
                    self.probe(new_row, new_col)
    return True

