def listActions(self, info=None, object=None):
    if object is not None or info is None:
        info = self._getOAI(object)
    chain = self.getChainFor(info.object)
    did = {}
    actions = []
    for wf_id in chain:
        did[wf_id] = 1
        wf = self.getWorkflowById(wf_id)
        if wf is not None:
            a = wf.listObjectActions(info)
            if a is not None:
                actions.extend(a)
            a = wf.listGlobalActions(info)
            if a is not None:
                actions.extend(a)
    wf_ids = self.getWorkflowIds()
    for wf_id in wf_ids:
        if wf_id not in did:
            wf = self.getWorkflowById(wf_id)
            if wf is not None:
                a = wf.listGlobalActions(info)
                if a is not None:
                    actions.extend(a)
    return actions

def init_weights(self, m):
    if type(m) == torch.nn.Linear:
        torch.nn.init.xavier_normal_(m.weight)
        torch.nn.init.zeros_(m.bias)
    elif type(m) == torch.nn.Conv2d:
        if (
            self.hparams["activation"] == "relu"
            and self.hparams["activation"] == "sigmoide"
        ):
            torch.nn.init.kaiming_normal_(
                m.weight, nonlinearity=self.hparams["activation"]
            )
        else:
            torch.nn.init.kaiming_normal_(m.weight)
        if not (m.bias is None):
            torch.nn.init.zeros_(m.bias)
    elif type(m) == torch.nn.BatchNorm2d:
        torch.nn.init.ones_(m.weight)
        torch.nn.init.zeros_(m.bias)

