def __matrix_from(header):
    try:
        space_directions = header["space directions"]
        space_origin = header["space origin"]
    except KeyError as e:
        raise IOError(
            'Need the header\'s "{}" field to determine the mapping from voxels to world coordinates.'.format(
                e
            )
        )
    trans_3x3 = np.array(space_directions).T
    trans_4x4 = np.eye(4)
    trans_4x4[:3, :3] = trans_3x3
    trans_4x4[:3, 3] = space_origin
    return trans_4x4

def _ExcludeDenylist(library_list, deny_list=[]):
    if not deny_list:
        return library_list
    return_list = []
    pattern = re.compile(r"|".join(deny_list))
    logging.debug("PATTERN: %s=", pattern)
    for library in library_list:
        if pattern.search(library):
            logging.debug("DENY-LISTED = %s=", library)
            continue
        return_list.append(library)
    logging.debug("Returning return_list=%s=", return_list)
    return return_list

def get_window_size(tsuid, ts_data, period):
    if period is None:
        raise TypeError("Period must be provided")
    if type(period) != int and period <= 0:
        raise ValueError("window period must be positive integer")
    if period >= (ts_data[-1][0] - ts_data[0][0]):
        raise ValueError(
            "window_period must be lower than TS window (%s)"
            % (ts_data[-1][0] - ts_data[0][0])
        )
    try:
        meta_data = IkatsApi.md.read(ts_list=[tsuid])
        if "qual_ref_period" in meta_data[tsuid]:
            window_size = ceil(period / meta_data[tsuid]["qual_ref_period"])
            LOGGER.debug("Period (%sms) -> Window size = %s", period, window_size)
            return window_size
    except Exception:
        pass
    LOGGER.debug("qual_ref_period metadata not found for TSUID:%s", tsuid)
    for i, _ in enumerate(ts_data):
        if (ts_data[i][0] - ts_data[0][0]) >= period:
            LOGGER.debug("Period (%sms) -> Window size = %s", period, i)
            return i
    raise ValueError("Window size is too big compared to TS length")

