def recreate_container(self, container, **override_options):
    try:
        container.stop()
    except APIError as e:
        if (
            e.response.status_code == 500
            and e.explanation
            and "no such process" in str(e.explanation)
        ):
            pass
        else:
            raise
    intermediate_container = Container.create(
        self.client,
        image=container.image,
        entrypoint=["/bin/echo"],
        command=[],
    )
    intermediate_container.start(volumes_from=container.id)
    intermediate_container.wait()
    container.remove()
    options = dict(override_options)
    new_container = self.create_container(**options)
    self.start_container(new_container, intermediate_container=intermediate_container)
    intermediate_container.remove()
    return (intermediate_container, new_container)

def theta(self):
    if self._is_variable_free:
        return self._private_children.Transform(lambda _: py_utils.NestedMap())
    if self._create_variables_status == _CreateLayerVariablesStatus.NOT_CALLED:
        raise ValueError(
            "Cannot access theta for layer %s before they have been created."
            % self.params.cls
        )
    stack_size = len(_THETA_STACK.stack)
    _THETA_STACK.stack.append(self)
    try:
        ret = self._InternalGetTheta()
    finally:
        assert _THETA_STACK.stack[-1] is self
        _THETA_STACK.stack.pop()
        assert len(_THETA_STACK.stack) == stack_size
    if not _THETA_STACK.stack:
        ret = self.AddGlobalVN(ret)
    return ret

