def _add_subtree(self, parent_id=None, tree=None):
    if parent_id is None:
        raise TreeError("Need node_id to connect to.")
    for st in tree:
        if type(st[0]) == list:  
            nd = self.dataclass()
            if (
                len(st[1]) >= 2
            ):  
                nd.support = st[1][0]
                if st[1][1] is not None:
                    nd.branchlength = st[1][1]
            elif (
                len(st[1]) == 1
            ):  
                if not self.__values_are_support:  
                    if st[1][0] is not None:
                        nd.branchlength = st[1][0]
                else:
                    nd.support = st[1][0]
            sn = Nodes.Node(nd)
            self.add(sn, parent_id)
            self._add_subtree(sn.id, st[0])
        else:  
            nd = self.dataclass()
            nd.taxon = st[0]
            if len(st) > 1:
                if (
                    len(st[1]) >= 2
                ):  
                    nd.support = st[1][0]
                    if st[1][1] is not None:
                        nd.branchlength = st[1][1]
                elif (
                    len(st[1]) == 1
                ):  
                    if not self.__values_are_support:  
                        if st[1][0] is not None:
                            nd.branchlength = st[1][0]
                    else:
                        nd.support = st[1][0]
            leaf = Nodes.Node(nd)
            self.add(leaf, parent_id)

def process_sim_html(self, content, destpath, **kwargs):
    content = content.replace(
        "check:function(){var t=this", "check:function(){return;var t=this"
    )
    content = content.replace(
        "getLinks:function(", "getLinks:function(){return [];},doNothing:function("
    )
    soup = BeautifulSoup(content, "html.parser")
    for script in soup.find_all("script"):
        if "analytics.js" in str(script):
            script.extract()
        if 'createTandem("phetWebsiteButton' in str(script):
            script.string = re.compile(
                '\{[^}]+createTandem\("phetWebsiteButton"\).*createTandem\("getUpdate"[^\}]*\},'
            ).sub("", script.string.replace("\n", " "))
    return str(soup)

def _compute_mean(
    self, C, S, mag, rrup, rvol, hypo_depth, CN, CR, f4HW, delta_C, delta_D
):
    lnSA_AB = self._compute_mean_on_rock(C, mag, rrup, rvol, hypo_depth, CN, CR, f4HW)
    lnSA_ABCD = lnSA_AB + S * self._compute_nonlinear_soil_term(
        C, lnSA_AB, delta_C, delta_D
    )
    return lnSA_ABCD

