def frames_to_kbits(
    frames: Iterable[Frame], seconds_start: int, seconds_end: int, seconds_offset: int
) -> Generator[Tuple[int, int], None, None]:
    frames_iter = iter(frames)
    last_frame_second = 0
    last_frame_size = 0
    for second in range(
        seconds_start + seconds_offset, seconds_end + seconds_offset + 1
    ):
        if last_frame_second == second:
            size = last_frame_size
        else:
            size = 0
        if last_frame_second <= second:
            for frame in frames_iter:
                frame_second = math.floor(frame.time)
                if frame_second < second:
                    continue
                if frame_second == second:
                    size += frame.size
                else:
                    last_frame_second = frame_second
                    last_frame_size = frame.size
                    break
        yield (second - seconds_offset), int(size * 8 / 1000)

