def receive(self, *buflen):
    not_ready = 0
    packet = ""
    if not buflen:
        buflen = 1024  
    packet_size = 0
    while True:
        if self.connection is not None or False:
            rdy = select.select([self.connection.fileno()], [], [], 0.3)[0]
            if rdy:
                try:
                    cpacket = self.connection.recv(buflen)
                    if not cpacket:
                        break
                except socket.error as ret_val:
                    self._manage_socket_error(ret_val)
                    return False
                cpacket_size = len(cpacket)
                packet_size = packet_size + cpacket_size
                if packet_size > 0:
                    packet = packet + cpacket
                else:
                    packet = cpacket
                continue
            else:
                not_ready = not_ready + 1
                if not_ready > 2:
                    break
        break
    return packet

def get_all_subclasses(klass):
