def manhattan_dist(mask):
    h, w = mask.shape
    man_dist = np.ones_like(mask) * (h + w - 2)
    for i in range(h):
        for j in range(w):
            if mask[i, j] == 1:
                man_dist[i, j] = 0
            else:
                if i > 0:
                    man_dist[i, j] = min(man_dist[i, j], man_dist[i - 1, j] + 1)
                if j > 0:
                    man_dist[i, j] = min(man_dist[i, j], man_dist[i, j - 1] + 1)
    for i in reversed(range(h)):
        for j in reversed(range(w)):
            if i < h - 1:
                man_dist[i, j] = min(man_dist[i, j], man_dist[i + 1, j] + 1)
            if j < w - 1:
                man_dist[i, j] = min(man_dist[i, j], man_dist[i, j + 1] + 1)
    return man_dist

