def _get_unbound_fn(method_or_fn: Callable[..., Any]) -> Callable[..., Any]:
    if inspect.ismethod(method_or_fn):
        method_or_fn = method_or_fn.__func__  
    if (
        not callable(method_or_fn)
        or len(inspect.signature(method_or_fn).parameters) < 1
