    ccw = kwargs.pop('ccw', False)
    close = kwargs.pop('close', False)
    radius = kwargs.pop('radius', None)
    x2 = y2 = None
    try:
        (x1,y1), (x2,y2), radius = parse_coords(coords, [Point,Point,float])
