    if not matches:
        if len(self.filtered_entries) > 0:
            raise NoMatchingPasswordError(
                format(
                    "No passwords matched the given arguments! (%s)",
                    concatenate(map(repr, arguments)),
                )
            )
        else:
            msg = "You don't have any passwords yet! (no *.gpg files found)"
            raise EmptyPasswordStoreError(msg)
    return matches

def intersection_BC(rho_i, D, B, C, value):
    m = (D - value) / (D + value)
    b = rho_i.l - m * rho_i.w
    L1 = line([rho_i.w, rho_i.l], [D, m * D + b])
    L2 = line([B.w, B.l], [C.w, C.l])
    return intersection(L1, L2)

