def epsilon_indicator_ndims(front: np.ndarray, reference_point: np.ndarray) -> list:
    min_eps = 0.0
    eps_list = np.zeros((front.shape[0]), dtype=numba.float64)
    for i in np.arange(front.shape[0]):
        value = np.max(reference_point - front[i])
