def get_data_loader(
    root, batch_size, split="train", shuffle=True, num_workers=4, pin_memory=False
):
    normalize = transforms.Normalize(
        mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]
    )
    val_test_transform = transforms.Compose([transforms.ToTensor(), normalize])
    train_transform = transforms.Compose(
        [
            transforms.RandomCrop(64, padding=4),
            transforms.RandomHorizontalFlip(),
            transforms.ToTensor(),
            normalize,
        ]
    )
    data_dir = root
    if split == "train":
        dataset = TinyImageNet(
            data_dir, split="train", transform=train_transform, in_memory=True
        )
    else:
        dataset = TinyImageNet(
            data_dir, split="val", transform=val_test_transform, in_memory=True
        )
    data_loader = torch.utils.data.DataLoader(
        dataset,
        batch_size=batch_size,
        num_workers=num_workers,
        pin_memory=pin_memory,
        shuffle=True,
    )
    return data_loader

def _set_field(self: object, data: str, size: int = 0, delimiter: list = []) -> None:
    field = data
    if delimiter:
        field += "".join(chr(c) for c in delimiter).encode("utf-8")
    field += b"\x00" * (size - len(field))
    if size:
        field = field[:size]
    self.data += field
